code_changes.content:
[
  {
    "file": "lib/base64.c",
    "line": 202,
    "severity": "critical",
    "description": "Missing integer overflow check for base64 encoding buffer allocation. On 32-bit systems, when insize > UINT_MAX/4 (approximately 1GB), the calculation '(insize + 2) / 3 * 4 + 1' can overflow, causing malloc to allocate a buffer much smaller than required. The encoding loop then writes beyond the allocated buffer, leading to heap buffer overflow. An attacker controlling the input size can trigger this vulnerability to cause memory corruption or code execution.",
    "fix_patch": "--- a/lib/base64.c
+++ b/lib/base64.c
@@ -199,6 +199,11 @@ static CURLcode base64_encode(const char *table64,
   if(!insize)
     insize = strlen(inputbuff);

+#if SIZEOF_SIZE_T == 4
+  if(insize > UINT_MAX/4)
+    return CURLE_OUT_OF_MEMORY;
+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 147,
    "severity": "critical",
    "description": "Incorrect cookie domain boundary check breaks RFC 6265 compliance. The check was changed from 'hostname + hostname_len - cookie_domain_len - 1' to 'hostname + hostname_len - cookie_domain_len', causing the code to examine the wrong buffer position. Instead of checking if the character BEFORE the domain match is a dot (required for subdomain matching), it checks the first character of the domain match itself. This causes the cookie_tailmatch function to incorrectly reject valid subdomain cookies (e.g., rejecting 'www.example.com' for 'example.com' domain), breaking legitimate cookie functionality and potentially allowing security bypass if workarounds cause cookies to be sent inappropriately.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -144,7 +144,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  }
]

